  1→import { stepCountIs, streamText, type ModelMessage } from "ai";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { ExtractedEntity, ExtractedRelationship, OnboardingState } from "../../shared/contracts";
  4→import { buildChatContext, buildSystemPrompt } from "./context";
  5→import { createChatAgentTools } from "./tools";
  6→
  7→type ConversationMessage = {
  8→  role: "user" | "assistant";
  9→  text: string;
 10→};
 11→
 12→type CollectedEntity = ExtractedEntity;
 13→type CollectedRelationship = ExtractedRelationship;
 14→
 15→export type ChatAgentResult = {
 16→  text: string;
 17→  collectedEntities: CollectedEntity[];
 18→  collectedRelationships: CollectedRelationship[];
 19→};
 20→
 21→export async function runChatAgent(input: {
 22→  surreal: Surreal;
 23→  model: any;
 24→  pmAgentModel: any;
 25→  analyticsAgentModel: any;
 26→  analyticsSurreal: Surreal;
 27→  embeddingModel: any;
 28→  embeddingDimension: number;
 29→  extractionModelId: string;
 30→  extractionModel: any;
 31→  extractionStoreThreshold: number;
 32→  conversationRecord: RecordId<"conversation", string>;
 33→  workspaceRecord: RecordId<"workspace", string>;
 34→  currentMessageRecord: RecordId<"message", string>;
 35→  latestUserText: string;
 36→  workspaceOwnerRecord?: RecordId<"person", string>;
 37→  inheritedEntityIds?: RecordId[];
 38→  discussesRecord?: RecordId;
 39→  messages: ConversationMessage[];
 40→  isOnboarding?: boolean;
 41→  onboardingState?: OnboardingState;
 42→  onToken: (token: string) => Promise<void> | void;
 43→}): Promise<ChatAgentResult> {
 44→  const context = await buildChatContext({
 45→    surreal: input.surreal,
 46→    conversationRecord: input.conversationRecord,
 47→    workspaceRecord: input.workspaceRecord,
 48→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 49→      ? { inheritedEntityIds: input.inheritedEntityIds }
 50→      : {}),
 51→    ...(input.discussesRecord ? { discussesRecord: input.discussesRecord } : {}),
 52→  });
 53→
 54→  const system = buildSystemPrompt(context, {
 55→    isOnboarding: input.isOnboarding,
 56→    onboardingState: input.onboardingState,
 57→  });
 58→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
 59→    role: message.role,
 60→    content: message.text,
 61→  }));
 62→
 63→  const result = streamText({
 64→    model: input.model,
 65→    system,
 66→    messages: modelMessages,
 67→    tools: createChatAgentTools({
 68→      surreal: input.surreal,
 69→      pmAgentModel: input.pmAgentModel,
 70→      analyticsAgentModel: input.analyticsAgentModel,
 71→      analyticsSurreal: input.analyticsSurreal,
 72→      embeddingModel: input.embeddingModel,
 73→      embeddingDimension: input.embeddingDimension,
 74→      extractionModelId: input.extractionModelId,
 75→      extractionModel: input.extractionModel,
 76→      extractionStoreThreshold: input.extractionStoreThreshold,
 77→    }),
 78→    experimental_context: {
 79→      actor: "chat_agent",
 80→      workspaceRecord: input.workspaceRecord,
 81→      conversationRecord: input.conversationRecord,
 82→      currentMessageRecord: input.currentMessageRecord,
 83→      latestUserText: input.latestUserText,
 84→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
 85→    },
 86→    stopWhen: stepCountIs(5),
 87→  });
 88→
 89→  let text = "";
 90→  const collectedEntities: CollectedEntity[] = [];
 91→  const collectedRelationships: CollectedRelationship[] = [];
 92→
 93→  for await (const part of result.fullStream) {
 94→    if (part.type === "text-delta") {
 95→      text = `${text}${part.text}`;
 96→      await input.onToken(part.text);
 97→      continue;
 98→    }
 99→
100→    if (part.type === "tool-result") {
101→      const toolResult = part.output as Record<string, unknown> | undefined;
102→      if (toolResult) {
103→        if (Array.isArray(toolResult.extracted_entities)) {
104→          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
105→        }
106→        if (Array.isArray(toolResult.extracted_relationships)) {
107→          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
108→        }
109→      }
110→    }
111→  }
112→
113→  if (text.trim().length === 0) {
114→    text = await result.text;
115→  }
116→
117→  return {
118→    text: text.trim(),
119→    collectedEntities,
120→    collectedRelationships,
121→  };
122→}
